#include <stdio.h>
#include <string.h>

int containsSubstring(char *mainStr, char *subStr) {
    if (strstr(mainStr, subStr) != NULL)
        return 1;
    return 0;
}

int main() {
    char str1[50] = "Programming";
    char str2[50] = "Program";
    char str3[50] = "Fundamentals";

    // strcmp() - Compare two strings
    int result = strcmp(str1, str2);
    if (result == 0)
        printf("str1 and str2 are equal\n");
    else if (result > 0)
        printf("str1 is greater than str2\n");
    else
        printf("str1 is less than str2\n");

    // strstr() - Find substring
    char *ptr = strstr(str1, "gram");
    if (ptr != NULL)
        printf("Substring 'gram' found at position: %ld\n", ptr - str1);

    // Custom function using strstr
    if (containsSubstring(str1, "gram"))
        printf("'gram' is a substring of 'Programming'\n");

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

void reverseString(char *str) {
    int left = 0;
    int right = strlen(str) - 1;
    char temp;

    while (left < right) {
        temp = str[left];
        str[left] = str[right];
        str[right] = temp;
        left++;
        right--;
    }
}

int isPalindrome(char *str) {
    int left = 0;
    int right = strlen(str) - 1;

    while (left < right) {
        if (tolower(str[left]) != tolower(str[right]))
            return 0;
        left++;
        right--;
    }
    return 1;
}

int main() {
    char str1[50] = "Programming";
    char str2[50] = "Madam";

    // String reversal
    printf("Original: %s\n", str1);
    reverseString(str1);
    printf("Reversed: %s\n", str1);

    // Palindrome check
    printf("\nChecking '%s': ", str2);
    if (isPalindrome(str2))
        printf("Palindrome\n");
    else
        printf("Not a palindrome\n");

    // Using string.h functions
